451→      WHEN $before.status != "pending_auth" AND $after.status = "pending_auth"
452→      THEN {
453→        http::post("${baseUrl}/api/intents/" + <string> meta::id($after.id) + "/evaluate", $after)
454→      };
455→  `);
456→}
