    const intentId = typeof body.id === "object" && body.id !== undefined
      ? (body.id.id as string)
      : undefined;

    if (!intentId) {
      return jsonError("Missing intent id in body", 400);
    }

    if (!body.requester) {
      return jsonError("Missing requester in intent body", 400);
