  1→import { jsonError, jsonResponse } from "../http/response";
  2→import { logError, logInfo } from "../http/observability";
  3→import { updateIntentStatus, listPendingIntents } from "./intent-queries";
  4→import { evaluateIntent, createLlmEvaluator } from "./authorizer";
  5→import { routeByRisk } from "./risk-router";
  6→import type { ServerDependencies } from "../runtime/types";
  7→import type { IntentRecord } from "./types";
  8→
  9→// --- Route Handler Types ---
 10→
 11→type IntentRouteHandlers = {
 12→  handleEvaluate: (request: Request) => Promise<Response>;
 13→  handleVeto: (workspaceId: string, intentId: string, request: Request) => Promise<Response>;
 14→  handleListPending: (workspaceId: string) => Promise<Response>;
 15→};
 16→
 17→// --- Factory ---
 18→
 19→export function createIntentRouteHandlers(deps: ServerDependencies): IntentRouteHandlers {
 20→  const { surreal } = deps;
 21→
 22→  const llmEvaluator = createLlmEvaluator(deps.extractionModel);
 23→
 24→  const handleEvaluate = async (request: Request): Promise<Response> => {
 25→    // Called by SurrealQL EVENT via http::post - receives full intent record as body
 26→    let body: IntentRecord;
 27→    try {
 28→      body = await request.json() as IntentRecord;
 29→    } catch {
 30→      return jsonError("Invalid JSON body", 400);
 31→    }
 32→
 33→    const intentId = typeof body.id === "object" && body.id !== undefined
 34→      ? (body.id.id as string)
 35→      : undefined;
 36→
 37→    if (!intentId) {
 38→      return jsonError("Missing intent id in body", 400);
 39→    }
 40→
 41→    if (!body.requester) {
 42→      return jsonError("Missing requester in intent body", 400);
 43→    }
 44→
 45→    logInfo("intent.evaluate.received", "Evaluate endpoint received intent", {
 46→      intentId,
 47→      status: body.status,
 48→      goal: body.goal,
 49→    });
 50→
 51→    // Idempotency guard: only process intents in pending_auth status
 52→    if (body.status !== "pending_auth") {
 53→      logInfo("intent.evaluate.skipped", "Intent not in pending_auth status", {
 54→        intentId,
 55→        currentStatus: body.status,
 56→      });
 57→      return jsonError(`Intent is in '${body.status}' status, expected 'pending_auth'`, 409);
 58→    }
 59→
 60→    try {
 61→      // Pipeline: policy gate -> LLM evaluator -> risk router -> status update
 62→      const requesterId = typeof body.requester === "object" && body.requester !== undefined
 63→        ? (body.requester.id as string)
 64→        : String(body.requester);
 65→
 66→      const evaluation = await evaluateIntent({
 67→        intent: {
 68→          goal: body.goal,
 69→          reasoning: body.reasoning,
 70→          action_spec: body.action_spec,
 71→          budget_limit: body.budget_limit,
 72→          requester: requesterId,
 73→        },
 74→        policy: {},
 75→        llmEvaluator,
 76→      });
 77→
 78→      const routing = routeByRisk(evaluation);
 79→      const evaluationRecord = {
 80→        ...evaluation,
 81→        evaluated_at: new Date(),
 82→      };
 83→
 84→      switch (routing.route) {
 85→        case "auto_approve": {
 86→          const result = await updateIntentStatus(surreal, intentId, "authorized", {
 87→            evaluation: evaluationRecord,
 88→          });
 89→          if (!result.ok) {
 90→            logError("intent.evaluate.update_failed", result.error, { intentId });
 91→            return jsonError(result.error, 409);
 92→          }
 93→          logInfo("intent.authorized", "Intent auto-approved", { intentId });
 94→          return jsonResponse({ intentId, status: "authorized", evaluation }, 200);
 95→        }
 96→
 97→        case "veto_window": {
 98→          const result = await updateIntentStatus(surreal, intentId, "pending_veto", {
 99→            evaluation: evaluationRecord,
100→            veto_expires_at: routing.expires_at,
101→          });
102→          if (!result.ok) {
103→            logError("intent.evaluate.update_failed", result.error, { intentId });
104→            return jsonError(result.error, 409);
105→          }
106→          logInfo("intent.pending_veto", "Intent requires veto window", {
107→            intentId,
108→            veto_expires_at: routing.expires_at.toISOString(),
109→          });
