158→// ===========================================================================
159→// 1. Workspace Overview (lightweight orientation, no params)
160→// ===========================================================================
161→
162→/** Build a lightweight workspace overview for agent orientation */
163→export async function buildWorkspaceOverview(input: {
164→  surreal: Surreal;
165→  workspaceRecord: RecordId<"workspace", string>;
166→  workspaceName: string;
167→  excludeSessionId?: string;
168→}): Promise<WorkspaceOverview> {
169→  const { surreal, workspaceRecord, workspaceName } = input;
170→
171→  const overviewQuery = `
172→    SELECT id, name, status, description
173→    FROM project
174→    WHERE id IN (SELECT VALUE out FROM has_project WHERE \`in\` = $workspace);
175→
176→    SELECT out AS project_id, record::tb(\`in\`) AS entity_type, count() AS count
177→    FROM belongs_to
178→    WHERE out IN (SELECT VALUE out FROM has_project WHERE \`in\` = $workspace)
179→    GROUP BY project_id, entity_type;
180→
181→    SELECT \`in\` AS project_id, count() AS count
182→    FROM has_feature
183→    WHERE \`in\` IN (SELECT VALUE out FROM has_project WHERE \`in\` = $workspace)
184→    GROUP BY project_id;
185→  `;
186→
187→  const [projectRows, entityCounts, featureCounts] = await surreal
188→    .query<[ProjectRow[], EntityCountRow[], FeatureCountRow[]]>(overviewQuery, {
189→      workspace: workspaceRecord,
190→    })
191→    .collect<[ProjectRow[], EntityCountRow[], FeatureCountRow[]]>();
192→
193→  const countsByProject = buildProjectCountMaps(entityCounts, featureCounts);
194→  const hotItems = await loadHotItems(surreal, workspaceRecord);
195→  const activeSessions = await loadActiveSessions(surreal, workspaceRecord, undefined, input.excludeSessionId);
196→
197→  return {
198→    workspace: { id: workspaceRecord.id as string, name: workspaceName },
199→    projects: projectRows.map((p) => ({
200→      id: toRawId(p.id),
201→      name: p.name,
202→      status: p.status,
203→      ...(p.description ? { description: p.description } : {}),
204→      counts: countsByProject.get(toRawId(p.id)) ?? { tasks: 0, decisions: 0, features: 0, questions: 0 },
205→    })),
206→    hot_items: hotItems,
207→    active_sessions: activeSessions,
208→  };
209→}
210→
211→function buildProjectCountMaps(
212→  entityCounts: EntityCountRow[],
213→  featureCounts: FeatureCountRow[],
214→): Map<string, { tasks: number; decisions: number; features: number; questions: number }> {
215→  const map = new Map<string, { tasks: number; decisions: number; features: number; questions: number }>();
216→
217→  for (const row of entityCounts) {
218→    const pid = toRawId(row.project_id);
219→    const entry = map.get(pid) ?? { tasks: 0, decisions: 0, features: 0, questions: 0 };
220→    if (row.entity_type === "task") entry.tasks = row.count;
221→    else if (row.entity_type === "decision") entry.decisions = row.count;
222→    else if (row.entity_type === "question") entry.questions = row.count;
223→    map.set(pid, entry);
224→  }
225→
226→  for (const row of featureCounts) {
227→    const pid = toRawId(row.project_id);
228→    const entry = map.get(pid) ?? { tasks: 0, decisions: 0, features: 0, questions: 0 };
229→    entry.features = row.count;
230→    map.set(pid, entry);
231→  }
232→
233→  return map;
234→}
235→
236→// ===========================================================================
237→// 2. Project Context (full project context, project_id required)
238→// ===========================================================================
239→
240→/** Build a full project context packet (decisions, tasks, questions, observations, suggestions) */
241→export async function buildProjectContext(input: {
242→  surreal: Surreal;
243→  workspaceRecord: RecordId<"workspace", string>;
244→  workspaceName: string;
245→  projectRecord: RecordId<"project", string>;
246→  taskId?: string;
247→  since?: string;
248→  excludeSessionId?: string;
249→}): Promise<ContextPacket> {
250→  const { surreal, workspaceRecord, workspaceName, projectRecord, taskId } = input;
251→
252→  const project = await surreal.select<ProjectRow>(projectRecord);
253→  if (!project) {
254→    throw new Error(`project not found: ${projectRecord.id}`);
255→  }
256→
257→  const projectEntitiesQuery = `
258→    LET $project_entity_ids = SELECT VALUE \`in\` FROM belongs_to WHERE out = $project;
259→
260→    SELECT id, summary, status, rationale, decided_at, category, priority, created_at
261→    FROM decision
262→    WHERE workspace = $workspace AND id IN $project_entity_ids
263→    ORDER BY created_at DESC LIMIT 50;
264→
265→    SELECT id, title, status, priority, category, description, source_session, created_at
266→    FROM task
267→    WHERE workspace = $workspace AND id IN $project_entity_ids
268→    ORDER BY created_at DESC LIMIT 50;
269→
270→    SELECT id, text, status, context, priority, created_at
271→    FROM question
272→    WHERE workspace = $workspace AND id IN $project_entity_ids
273→    ORDER BY created_at DESC LIMIT 30;
274→
275→    SELECT id, text, severity, status, category, observation_type, created_at
276→    FROM observation
277→    WHERE workspace = $workspace AND status IN ["open", "acknowledged"]
278→    ORDER BY created_at DESC LIMIT 20;
279→
280→    SELECT id, text, category, rationale, confidence, status, suggested_by, created_at
281→    FROM suggestion
282→    WHERE workspace = $workspace AND status IN ["pending", "deferred"]
283→    ORDER BY confidence DESC, created_at DESC LIMIT 15;
284→  `;
285→
286→  const results = await surreal
287→    .query<[null, DecisionRow[], TaskRow[], QuestionRow[], ObservationRow[], SuggestionRow[]]>(projectEntitiesQuery, {
288→      project: projectRecord,
289→      workspace: workspaceRecord,
290→    })
291→    .collect<[null, DecisionRow[], TaskRow[], QuestionRow[], ObservationRow[], SuggestionRow[]]>();
292→
293→  const [, decisionRows, taskRows, questionRows, observationRows, suggestionRows] = results;
294→
295→  // Categorize decisions by status
296→  const confirmed: DecisionContext[] = [];
297→  const provisional: DecisionContext[] = [];
298→  const contested: DecisionContext[] = [];
299→
300→  for (const d of decisionRows) {
301→    const ctx: DecisionContext = {
302→      id: toRawId(d.id),
303→      summary: d.summary,
304→      status: d.status,
305→      ...(d.rationale ? { rationale: d.rationale } : {}),
306→      ...(d.decided_at ? { decided_at: toIso(d.decided_at) } : {}),
307→      ...(d.category ? { category: d.category } : {}),
308→      ...(d.priority ? { priority: d.priority } : {}),
309→    };
310→
311→    if (d.status === "contested") {
312→      contested.push(ctx);
313→    } else if (d.status === "provisional" || d.status === "inferred") {
314→      provisional.push(ctx);
315→    } else if (d.status === "confirmed") {
316→      confirmed.push(ctx);
317→    }
318→  }
319→
320→  const activeTasks: TaskContext[] = taskRows
321→    .filter((t) => t.status !== "done" && t.status !== "completed")
322→    .map((t) => ({
323→      id: toRawId(t.id),
324→      title: t.title,
325→      status: t.status,
326→      ...(t.priority ? { priority: t.priority } : {}),
327→      ...(t.category ? { category: t.category } : {}),
328→      ...(t.source_session ? { source_session: toRawId(t.source_session) } : {}),
329→    }));
330→
331→  const openQuestions: QuestionContext[] = questionRows
332→    .filter((q) => q.status !== "answered" && q.status !== "resolved")
333→    .map((q) => ({
334→      id: toRawId(q.id),
335→      text: q.text,
336→      status: q.status,
337→      ...(q.context ? { context: q.context } : {}),
338→      ...(q.priority ? { priority: q.priority } : {}),
339→    }));
340→
341→  const observations: ObservationContext[] = observationRows.map((o) => ({
342→    id: toRawId(o.id),
343→    text: o.text,
344→    severity: o.severity,
345→    status: o.status,
346→    ...(o.category ? { category: o.category } : {}),
347→    ...(o.observation_type ? { observation_type: o.observation_type } : {}),
348→  }));
349→
350→  const pendingSuggestions: SuggestionContext[] = suggestionRows.map((s) => ({
351→    id: toRawId(s.id),
352→    text: s.text,
353→    category: s.category,
354→    rationale: s.rationale,
355→    confidence: s.confidence,
356→    status: s.status,
357→    suggested_by: s.suggested_by,
358→    created_at: toIso(s.created_at),
359→  }));
360→
361→  const activeSessions = await loadActiveSessions(surreal, workspaceRecord, projectRecord, input.excludeSessionId);
362→
363→  const recentChanges: RecentChangeContext[] = input.since
364→    ? await loadRecentChanges(surreal, workspaceRecord, projectRecord, input.since)
365→    : [];
366→
367→  let taskScope: TaskScopeContext | undefined;
368→  if (taskId) {
369→    taskScope = await buildTaskScope(surreal, workspaceRecord, taskId);
370→  }
371→
372→  return {
373→    workspace: { id: workspaceRecord.id as string, name: workspaceName },
374→    project: {
375→      id: projectRecord.id as string,
376→      name: project.name,
377→      status: project.status,
378→      ...(project.description ? { description: project.description } : {}),
379→    },
380→    ...(taskScope ? { task_scope: taskScope } : {}),
381→    decisions: { confirmed, provisional, contested },
382→    active_tasks: activeTasks,
383→    open_questions: openQuestions,
384→    recent_changes: recentChanges,
385→    observations,
386→    pending_suggestions: pendingSuggestions,
387→    active_sessions: activeSessions,
388→  };
389→}
390→
391→// ===========================================================================
392→// 3. Task Context (task-focused, task_id required, project resolved from graph)
393→// ===========================================================================
394→
395→/** Build task-focused context: task subgraph + project hot items */
396→export async function buildTaskContext(input: {
397→  surreal: Surreal;
398→  workspaceRecord: RecordId<"workspace", string>;
399→  workspaceName: string;
400→  taskId: string;
401→  excludeSessionId?: string;
402→}): Promise<TaskContextPacket> {
403→  const { surreal, workspaceRecord, workspaceName, taskId } = input;
404→
405→  const taskRecord = new RecordId("task", taskId);
406→  const task = await surreal.select<TaskRow & { workspace: RecordId<"workspace", string> }>(taskRecord);
407→  if (!task) {
408→    throw new Error(`task not found: ${taskId}`);
409→  }
410→  if ((task.workspace.id as string) !== (workspaceRecord.id as string)) {
411→    throw new Error(`task not in workspace: ${taskId}`);
412→  }
413→
414→  // Resolve project from belongs_to edge
415→  const [projectEdges] = await surreal
416→    .query<[Array<{ out: RecordId<"project", string> }>]>(
417→      `SELECT out FROM belongs_to WHERE \`in\` = $task AND record::tb(out) = "project" LIMIT 1;`,
418→      { task: taskRecord },
419→    )
420→    .collect<[Array<{ out: RecordId<"project", string> }>]>();
421→
422→  let projectInfo: { id: string; name: string; status: string };
423→  let projectRecord: RecordId<"project", string> | undefined;
424→
425→  if (projectEdges.length > 0) {
426→    projectRecord = projectEdges[0].out;
427→    const project = await surreal.select<ProjectRow>(projectRecord);
428→    if (project) {
429→      projectInfo = { id: toRawId(project.id), name: project.name, status: project.status };
430→    } else {
431→      projectInfo = { id: toRawId(projectRecord), name: "unknown", status: "unknown" };
432→    }
433→  } else {
434→    projectInfo = { id: "unassigned", name: "unassigned", status: "unknown" };
435→  }
436→
437→  const taskScope = await buildTaskScope(surreal, workspaceRecord, taskId);
438→  const hotItems = await loadHotItems(surreal, workspaceRecord, projectRecord);
439→  const activeSessions = await loadActiveSessions(surreal, workspaceRecord, projectRecord, input.excludeSessionId);
440→
441→  return {
442→    workspace: { id: workspaceRecord.id as string, name: workspaceName },
443→    project: projectInfo,
444→    task_scope: taskScope,
445→    hot_items: hotItems,
446→    active_sessions: activeSessions,
447→  };
448→}
449→
450→// ===========================================================================
451→// Shared helpers
452→// ===========================================================================
453→
454→/** Load hot items: contested decisions, open observations, pending suggestions */
455→async function loadHotItems(
456→  surreal: Surreal,
457→  workspaceRecord: RecordId<"workspace", string>,
458→  projectRecord?: RecordId<"project", string>,
459→): Promise<HotItems> {
460→  // When project-scoped, filter decisions via belongs_to
461→  const decisionFilter = projectRecord
462→    ? `AND id IN (SELECT VALUE \`in\` FROM belongs_to WHERE out = $project)`
463→    : "";
464→
465→  const hotQuery = `
466→    SELECT id, summary, updated_at
467→    FROM decision
468→    WHERE workspace = $workspace AND status = "contested" ${decisionFilter}
469→    ORDER BY updated_at DESC LIMIT 10;
470→
471→    SELECT id, text, severity, category, created_at
472→    FROM observation
473→    WHERE workspace = $workspace AND status IN ["open", "acknowledged"] AND severity IN ["warning", "conflict"]
474→    ORDER BY created_at DESC LIMIT 10;
475→
476→    SELECT id, text, category, confidence, created_at
477→    FROM suggestion
478→    WHERE workspace = $workspace AND status = "pending"
479→    ORDER BY confidence DESC, created_at DESC LIMIT 5;
480→  `;
481→
482→  const [contestedDecisions, hotObservations, hotSuggestions] = await surreal
483→    .query<[ContestedDecisionRow[], HotObservationRow[], HotSuggestionRow[]]>(hotQuery, {
484→      workspace: workspaceRecord,
485→      ...(projectRecord ? { project: projectRecord } : {}),
486→    })
487→    .collect<[ContestedDecisionRow[], HotObservationRow[], HotSuggestionRow[]]>();
488→
489→  return {
490→    contested_decisions: contestedDecisions.map((d) => ({
491→      id: toRawId(d.id),
492→      summary: d.summary,
493→    })),
494→    open_observations: hotObservations.map((o) => ({
495→      id: toRawId(o.id),
496→      text: o.text,
497→      severity: o.severity,
498→      ...(o.category ? { category: o.category } : {}),
499→    })),
500→    pending_suggestions: hotSuggestions.map((s) => ({
501→      id: toRawId(s.id),
502→      text: s.text,
503→      category: s.category,
504→      confidence: s.confidence,
505→    })),
506→  };
507→}
508→
509→/** Build task-scoped context: subtasks, parent feature, siblings, dependencies, related sessions */
510→async function buildTaskScope(
511→  surreal: Surreal,
512→  workspaceRecord: RecordId<"workspace", string>,
513→  taskId: string,
514→): Promise<TaskScopeContext> {
515→  const taskRecord = new RecordId("task", taskId);
516→  const task = await surreal.select<TaskRow & { workspace: RecordId<"workspace", string> }>(taskRecord);
517→  if (!task) {
518→    throw new Error(`task not found: ${taskId}`);
519→  }
520→  if ((task.workspace.id as string) !== (workspaceRecord.id as string)) {
521→    throw new Error(`task not in workspace: ${taskId}`);
522→  }
523→
524→  const taskScopeQuery = `
525→    SELECT id, title, status, created_at
526→    FROM task
527→    WHERE id IN (SELECT VALUE \`in\` FROM subtask_of WHERE out = $task)
528→    ORDER BY created_at ASC;
529→
530→    SELECT id, name, description
531→    FROM feature
532→    WHERE id IN (SELECT VALUE \`in\` FROM has_task WHERE out = $task)
533→    LIMIT 1;
534→
535→    SELECT id, title, status
536→    FROM task
537→    WHERE id IN (SELECT VALUE out FROM depends_on WHERE \`in\` = $task);
538→
539→    SELECT id, agent, ended_at, summary
540→    FROM agent_session
541→    WHERE task_id = $task AND ended_at != NONE
542→    ORDER BY ended_at DESC LIMIT 5;
543→  `;
544→
545→  const results = await surreal
546→    .query<[SubtaskRow[], FeatureRow[], DependencyRow[], AgentSessionRow[]]>(taskScopeQuery, {
547→      task: taskRecord,
548→    })
549→    .collect<[SubtaskRow[], FeatureRow[], DependencyRow[], AgentSessionRow[]]>();
550→
551→  const [subtaskRows, featureRows, dependencyRows, sessionRows] = results;
552→
553→  const parentFeature = featureRows.length > 0
554→    ? {
555→        id: toRawId(featureRows[0].id),
556→        name: featureRows[0].name,
557→        ...(featureRows[0].description ? { description: featureRows[0].description } : {}),
558→      }
559→    : undefined;
560→
561→  let siblingTasks: { id: string; title: string; status: string; source_session?: string }[] = [];
562→  if (parentFeature && featureRows.length > 0) {
563→    const [siblingRows] = await surreal
564→      .query<[TaskRow[]]>(
565→        `SELECT id, title, status, source_session, created_at FROM task
566→         WHERE id IN (SELECT VALUE out FROM has_task WHERE \`in\` = $feature)
567→           AND id != $task
568→         ORDER BY created_at ASC LIMIT 20;`,
569→        { feature: featureRows[0].id, task: taskRecord },
570→      )
571→      .collect<[TaskRow[]]>();
572→
573→    siblingTasks = siblingRows.map((t) => ({
574→      id: toRawId(t.id),
575→      title: t.title,
576→      status: t.status,
577→      ...(t.source_session ? { source_session: toRawId(t.source_session) } : {}),
578→    }));
579→  }
580→
581→  return {
582→    task: {
583→      id: toRawId(task.id),
584→      title: task.title,
585→      ...(task.description ? { description: task.description } : {}),
586→      status: task.status,
587→      ...(task.category ? { category: task.category } : {}),
588→    },
589→    subtasks: subtaskRows.map((s) => ({
590→      id: toRawId(s.id),
591→      title: s.title,
592→      status: s.status,
593→    })),
594→    parent_feature: parentFeature,
595→    sibling_tasks: siblingTasks,
596→    dependencies: dependencyRows.map((d) => ({
597→      id: toRawId(d.id),
598→      title: d.title,
599→      status: d.status,
600→    })),
601→    related_sessions: sessionRows.map((s) => ({
602→      id: toRawId(s.id),
603→      agent: s.agent,
604→      ended_at: toIso(s.ended_at),
605→      summary: s.summary ?? "",
606→    })),
607→  };
608→}
609→
610→/** Load active agent sessions, optionally scoped to a project */
611→async function loadActiveSessions(
612→  surreal: Surreal,
613→  workspaceRecord: RecordId<"workspace", string>,
614→  projectRecord?: RecordId<"project", string>,
615→  excludeSessionId?: string,
616→): Promise<ActiveSessionContext[]> {
617→  const excludeRecord = excludeSessionId
618→    ? new RecordId("agent_session", excludeSessionId)
619→    : new RecordId("agent_session", "__none__");
620→
621→  const projectFilter = projectRecord ? "AND project = $project" : "";
622→  const [sessionRows] = await surreal
623→    .query<[ActiveAgentSessionRow[]]>(
624→      `SELECT id, agent, started_at, task_id
625→       FROM agent_session
626→       WHERE workspace = $workspace ${projectFilter} AND ended_at = NONE AND id != $exclude
627→       ORDER BY started_at DESC LIMIT 10;`,
628→      { workspace: workspaceRecord, ...(projectRecord ? { project: projectRecord } : {}), exclude: excludeRecord },
629→    )
630→    .collect<[ActiveAgentSessionRow[]]>();
631→
632→  if (sessionRows.length === 0) return [];
633→
634→  const sessionIds = sessionRows.map((s) => s.id);
635→
636→  const [observationRows] = await surreal
637→    .query<[SessionObservationRow[]]>(
638→      `SELECT id, text, severity, source_session FROM observation
639→       WHERE source_session IN $sessions
640→         AND status IN ["open", "acknowledged"];`,
641→      { sessions: sessionIds },
642→    )
643→    .collect<[SessionObservationRow[]]>();
644→
645→  const taskIds = sessionRows
646→    .filter((s) => s.task_id)
647→    .map((s) => s.task_id!);
648→
649→  let taskTitles: Map<string, string> = new Map();
650→  if (taskIds.length > 0) {
651→    const [taskRows] = await surreal
652→      .query<[Array<{ id: RecordId<"task", string>; title: string }>]>(
653→        `SELECT id, title FROM task WHERE id IN $tasks;`,
654→        { tasks: taskIds },
655→      )
656→      .collect<[Array<{ id: RecordId<"task", string>; title: string }>]>();
657→    taskTitles = new Map(taskRows.map((t) => [toRawId(t.id), t.title]));
658→  }
659→
660→  const obsBySession = new Map<string, Array<{ id: string; text: string; severity: string }>>();
661→  for (const o of observationRows) {
662→    const sessionKey = toRawId(o.source_session);
663→    const arr = obsBySession.get(sessionKey) ?? [];
664→    arr.push({ id: toRawId(o.id), text: o.text, severity: o.severity });
665→    obsBySession.set(sessionKey, arr);
666→  }
667→
668→  const decisionsBySession = new Map<string, Array<{ id: string; summary: string }>>();
669→  for (const session of sessionRows) {
670→    const sessionKey = toRawId(session.id);
671→    const [decisionRows] = await surreal
672→      .query<[Array<{ id: RecordId<"decision", string>; summary: string }>]>(
673→        `SELECT id, summary FROM decision
674→         WHERE id IN (SELECT VALUE out FROM produced WHERE \`in\` = $session)
675→           AND status = "provisional";`,
676→        { session: session.id },
677→      )
678→      .collect<[Array<{ id: RecordId<"decision", string>; summary: string }>]>();
679→
680→    decisionsBySession.set(
681→      sessionKey,
682→      decisionRows.map((d) => ({ id: toRawId(d.id), summary: d.summary })),
683→    );
684→  }
685→
686→  return sessionRows.map((s) => {
687→    const sessionKey = toRawId(s.id);
688→    const taskId = s.task_id ? toRawId(s.task_id) : undefined;
689→    return {
690→      id: sessionKey,
691→      agent: s.agent,
692→      started_at: toIso(s.started_at),
693→      ...(taskId && taskTitles.has(taskId)
694→        ? { task: { id: taskId, title: taskTitles.get(taskId)! } }
695→        : {}),
696→      provisional_decisions: decisionsBySession.get(sessionKey) ?? [],
697→      observations: obsBySession.get(sessionKey) ?? [],
698→    };
699→  });
700→}
701→
702→/** Load entities changed since a timestamp (project-scoped) */
703→async function loadRecentChanges(
704→  surreal: Surreal,
705→  workspaceRecord: RecordId<"workspace", string>,
706→  projectRecord: RecordId<"project", string>,
707→  since: string,
708→): Promise<RecentChangeContext[]> {
709→  const sinceDate = new Date(since);
710→
711→  const query = `
712→    LET $project_entity_ids = SELECT VALUE \`in\` FROM belongs_to WHERE out = $project;
713→
714→    LET $recent_decisions = SELECT "decision" AS entity_type, summary AS entity_name, status AS change_type, updated_at AS changed_at
715→    FROM decision
716→    WHERE workspace = $workspace AND id IN $project_entity_ids AND updated_at > $since
717→    ORDER BY updated_at DESC LIMIT 20;
718→
719→    LET $recent_tasks = SELECT "task" AS entity_type, title AS entity_name, status AS change_type, updated_at AS changed_at
720→    FROM task
721→    WHERE workspace = $workspace AND id IN $project_entity_ids AND updated_at > $since
722→    ORDER BY updated_at DESC LIMIT 20;
723→
724→    LET $recent_questions = SELECT "question" AS entity_type, text AS entity_name, status AS change_type, updated_at AS changed_at
725→    FROM question
726→    WHERE workspace = $workspace AND id IN $project_entity_ids AND updated_at > $since
727→    ORDER BY updated_at DESC LIMIT 20;
728→
729→    LET $recent_observations = SELECT "observation" AS entity_type, text AS entity_name, severity AS change_type, updated_at AS changed_at
730→    FROM observation
731→    WHERE workspace = $workspace AND updated_at > $since
732→    ORDER BY updated_at DESC LIMIT 20;
733→
734→    LET $recent_suggestions = SELECT "suggestion" AS entity_type, text AS entity_name, status AS change_type, updated_at AS changed_at
735→    FROM suggestion
736→    WHERE workspace = $workspace AND updated_at > $since
737→    ORDER BY updated_at DESC LIMIT 20;
738→
739→    RETURN array::flatten([$recent_decisions, $recent_tasks, $recent_questions, $recent_observations, $recent_suggestions]);
740→  `;
741→
742→  const results = await surreal
743→    .query<[null, null, null, null, null, null, RecentChangeRow[]]>(query, {
744→      project: projectRecord,
745→      workspace: workspaceRecord,
746→      since: sinceDate,
747→    })
748→    .collect<[null, null, null, null, null, null, RecentChangeRow[]]>();
749→
750→  const rows = results[6] ?? [];
751→
752→  return rows.map((r) => ({
753→    entity_type: r.entity_type,
754→    entity_name: r.entity_name,
755→    change_type: r.change_type,
756→    changed_at: toIso(r.changed_at),
757→  }));
758→}
