import { RecordId, type Surreal } from "surrealdb";
import type {
  ContextPacket,
  DecisionContext,
  TaskContext,
  QuestionContext,
  ObservationContext,
  SuggestionContext,
  ActiveSessionContext,
  TaskScopeContext,
  RecentChangeContext,
  WorkspaceOverview,
  TaskContextPacket,
  HotItems,
} from "./types";
import { toRawId } from "./id-format";

// ---------------------------------------------------------------------------
// Row types (private)
// ---------------------------------------------------------------------------

type ProjectRow = {
  id: RecordId<"project", string>;
  name: string;
  status: string;
  description?: string;
};

type DecisionRow = {
  id: RecordId<"decision", string>;
  summary: string;
  status: string;
  rationale?: string;
  decided_at?: Date | string;
  category?: string;
  priority?: string;
};

type TaskRow = {
  id: RecordId<"task", string>;
  title: string;
  status: string;
  priority?: string;
  category?: string;
  description?: string;
  source_session?: RecordId<"agent_session", string>;
};

type QuestionRow = {
  id: RecordId<"question", string>;
  text: string;
  status: string;
  context?: string;
  priority?: string;
};

type ObservationRow = {
  id: RecordId<"observation", string>;
  text: string;
  severity: string;
  status: string;
  category?: string;
  observation_type?: string;
};

type SuggestionRow = {
  id: RecordId<"suggestion", string>;
  text: string;
  category: string;
  rationale: string;
  confidence: number;
  status: string;
  suggested_by: string;
  created_at: Date | string;
};

