  id: RecordId<"agent_session", string>;
  agent: string;
  ended_at?: Date | string;
  summary?: string;
};

type SubtaskRow = {
  id: RecordId<"task", string>;
  title: string;
  status: string;
};

type FeatureRow = {
  id: RecordId<"feature", string>;
  name: string;
  description?: string;
};

type DependencyRow = {
  id: RecordId<"task", string>;
